#include "hirct/Target/GenRAL.h"
#include "hirct/Analysis/IRAnalysis.h"

#include <cctype>
#include <cerrno>
#include <cstring>
#include <fstream>
#include <iomanip>
#include <iostream>
#include <sstream>
#include <sys/stat.h>

namespace hirct {

static constexpr const char *AUTO_GENERATED_HEADER =
    "// AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

GenRAL::GenRAL(circt::hw::HWModuleOp hw_module)
    : hw_module_(hw_module), registers_(hirct::collect_registers(hw_module)) {}

bool GenRAL::should_skip() const { return registers_.empty(); }

std::string GenRAL::to_upper(const std::string &s) const {
  std::string r;
  r.reserve(s.size());
  for (char c : s)
    r += static_cast<char>(toupper(static_cast<unsigned char>(c)));
  return r;
}

std::string GenRAL::to_lower(const std::string &s) const {
  std::string r;
  r.reserve(s.size());
  for (char c : s)
    r += static_cast<char>(tolower(static_cast<unsigned char>(c)));
  return r;
}

bool GenRAL::emit(const std::string &output_dir) {
  if (should_skip()) {
    return true;
  }

  std::string ral_dir = output_dir + "/ral";
  if (mkdir(ral_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    std::cerr << "GenRAL: cannot create directory: " << ral_dir << ": "
              << strerror(errno) << "\n";
    return false;
  }

  if (!emit_ral_sv(ral_dir))
    return false;
  if (!emit_hal_h(ral_dir))
    return false;
  if (!emit_driver_c(ral_dir))
    return false;
  return true;
}

// ---------------------------------------------------------------------------
// emit_ral_sv — generates <ModuleName>_ral.sv (UVM reg_block)
// ---------------------------------------------------------------------------

bool GenRAL::emit_ral_sv(const std::string &dir) {
  std::string name = hw_module_.getSymName().str();
  std::string path = dir + "/" + name + "_ral.sv";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenRAL: cannot open " << path << "\n";
    return false;
  }

  std::string block_name = name + "_reg_block";

  ofs << AUTO_GENERATED_HEADER;
  ofs << "import uvm_pkg::*;\n\n";

  for (const auto &reg : registers_) {
    std::string reg_class = reg.name + "_reg";
    ofs << "class " << reg_class << " extends uvm_reg;\n";
    ofs << "  `uvm_object_utils(" << reg_class << ")\n\n";
    ofs << "  uvm_reg_field data;\n\n";
    ofs << "  function new(string name = \"" << reg_class << "\");\n";
    ofs << "    super.new(name, " << reg.width << ", UVM_NO_COVERAGE);\n";
    ofs << "  endfunction\n\n";
    ofs << "  virtual function void build();\n";
    ofs << "    data = uvm_reg_field::type_id::create(\"data\");\n";
    ofs << "    data.configure(this, " << reg.width << ", 0, \"RW\", 0, "
        << reg.width << "'h0, 1, 1, 1);\n";
    ofs << "  endfunction\n";
    ofs << "endclass\n\n";
  }

  ofs << "class " << block_name << " extends uvm_reg_block;\n";
  ofs << "  `uvm_object_utils(" << block_name << ")\n\n";

  uint32_t offset = 0;
  for (const auto &reg : registers_) {
    std::ostringstream hex;
    hex << "0x" << std::setfill('0') << std::setw(2) << std::hex << offset;
    ofs << "  " << reg.name << "_reg " << reg.name << ";  // offset "
        << hex.str() << ", width " << reg.width << "\n";
    offset += 4;
  }

  ofs << "\n";
  ofs << "  function new(string name = \"" << block_name << "\");\n";
  ofs << "    super.new(name, UVM_NO_COVERAGE);\n";
  ofs << "  endfunction\n\n";
  ofs << "  virtual function void build();\n";

  for (const auto &reg : registers_) {
    ofs << "    " << reg.name << " = " << reg.name << "_reg::type_id::create(\""
        << reg.name << "\");\n";
    ofs << "    " << reg.name << ".configure(this, null, \"\");\n";
    ofs << "    " << reg.name << ".build();\n";
  }

  ofs << "    default_map = create_map(\"default_map\", 0, 4, "
         "UVM_LITTLE_ENDIAN);\n";

  offset = 0;
  for (const auto &reg : registers_) {
    std::ostringstream hex;
    hex << std::hex << offset;
    ofs << "    default_map.add_reg(" << reg.name << ", 'h" << hex.str()
        << ", \"RW\");\n";
    offset += 4;
  }

  ofs << "  endfunction\n";
  ofs << "endclass\n";
  return true;
}

// ---------------------------------------------------------------------------
// emit_hal_h — generates <ModuleName>_hal.h (C HAL header)
// ---------------------------------------------------------------------------

bool GenRAL::emit_hal_h(const std::string &dir) {
  std::string name = hw_module_.getSymName().str();
  std::string upper = to_upper(name);
  std::string lower = to_lower(name);
  std::string path = dir + "/" + name + "_hal.h";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenRAL: cannot open " << path << "\n";
    return false;
  }

  std::string guard = upper + "_HAL_H";

  ofs << AUTO_GENERATED_HEADER;
  ofs << "#ifndef " << guard << "\n";
  ofs << "#define " << guard << "\n";
  ofs << "#include <stdint.h>\n\n";

  ofs << "// Register offsets (base address injected at use site)\n";
  uint32_t offset = 0;
  for (const auto &reg : registers_) {
    std::string reg_upper = to_upper(reg.name);
    std::ostringstream hex;
    hex << "0x" << std::setfill('0') << std::setw(2) << std::hex << offset;
    ofs << "#define " << upper << "_REG_" << reg_upper << "_OFFSET  "
        << hex.str() << "\n";
    offset += 4;
  }

  ofs << "\n// Access helpers\n";
  ofs << "static inline uint32_t " << lower
      << "_read(volatile void* base, uint32_t offset) {\n";
  ofs << "    return *(volatile uint32_t*)((uint8_t*)base + offset);\n";
  ofs << "}\n";
  ofs << "static inline void " << lower
      << "_write(volatile void* base, uint32_t offset, uint32_t val) {\n";
  ofs << "    *(volatile uint32_t*)((uint8_t*)base + offset) = val;\n";
  ofs << "}\n\n";

  ofs << "// Convenience macros\n";
  for (const auto &reg : registers_) {
    std::string reg_upper = to_upper(reg.name);
    ofs << "#define " << upper << "_READ_" << reg_upper << "(base)        "
        << lower << "_read(base, " << upper << "_REG_" << reg_upper
        << "_OFFSET)\n";
    ofs << "#define " << upper << "_WRITE_" << reg_upper << "(base, val)  "
        << lower << "_write(base, " << upper << "_REG_" << reg_upper
        << "_OFFSET, val)\n";
  }

  ofs << "#endif // " << guard << "\n";
  return true;
}

// ---------------------------------------------------------------------------
// emit_driver_c — generates <ModuleName>_driver.c (C driver)
// ---------------------------------------------------------------------------

bool GenRAL::emit_driver_c(const std::string &dir) {
  std::string name = hw_module_.getSymName().str();
  std::string upper = to_upper(name);
  std::string lower = to_lower(name);
  std::string path = dir + "/" + name + "_driver.c";

  std::ofstream ofs(path);
  if (!ofs) {
    std::cerr << "GenRAL: cannot open " << path << "\n";
    return false;
  }

  ofs << AUTO_GENERATED_HEADER;
  ofs << "#include \"" << name << "_hal.h\"\n\n";
  ofs << "void " << lower << "_init(volatile void* base) {\n";
  for (const auto &reg : registers_) {
    std::string reg_upper = to_upper(reg.name);
    ofs << "    " << lower << "_write(base, " << upper << "_REG_" << reg_upper
        << "_OFFSET, 0x0);\n";
  }
  ofs << "}\n";
  return true;
}

} // namespace hirct
